---

## Complete Implementation Plan for the Stepper Compound Component

### Overview

Four changes are required, in this order:

1. **Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`** -- the compound component
2. **Create `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`** -- the demo
3. **Edit `apps/v4/registry/new-york-v4/ui/_registry.ts`** -- insert UI entry after line 563
4. **Edit `apps/v4/registry/new-york-v4/examples/_registry.ts`** -- insert example entry after line 2124

---

### 1. File: `stepper.tsx` -- Detailed Architecture

#### Two Contexts Required

The stepper needs **two** React contexts:

**StepperContext** (provided by `Stepper` root):
```typescript
type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}
```

**StepperItemContext** (provided by each `StepperItem`):
```typescript
type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}
```

The `StepperItemContext` is the key design decision. `StepperItem` computes the state by comparing its `step` prop against `activeStep` from the parent context, then provides both `step` and `state` to its children. This is how `StepperTrigger` gets the step number and `StepperSeparator` determines its visual state.

#### Exact Code for `stepper.tsx`

```typescript
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep, orientation } = useStepper()

  const state =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-2",
          orientation === "horizontal" ? "flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/25 bg-transparent text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (state === "completed" ? <CheckIcon className="size-4" /> : step)}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium",
        state === "pending" ? "text-muted-foreground" : "text-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      className={cn(
        "shrink-0 bg-border transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" ? "h-0.5 w-full min-w-4 flex-1" : "mx-auto h-4 w-0.5",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

#### Key Design Decisions Explained

**How StepperTrigger gets the step number**: `StepperTrigger` calls `useStepperItem()` which reads from `StepperItemContext`. The `StepperItem` component computes `state` from `step` vs `activeStep` and passes both `step` and `state` into the `StepperItemContext.Provider`. This means `StepperTrigger` does **not** need its own `step` prop -- it inherits it from its parent `StepperItem` via context. The trigger renders `step` (the number) as its default children, or a `CheckIcon` when completed, or user-supplied children when provided.

**How StepperSeparator determines state**: `StepperSeparator` also calls `useStepperItem()`. It is placed **inside** a `StepperItem`, so it inherits that item's `state`. The convention is that the separator "belongs to" the step it visually follows. When `data-state="completed"`, the separator turns `bg-primary` (filled). When active or pending, it stays `bg-border` (unfilled). This naturally means the separator between step 1 and step 2 fills when step 1 is completed (i.e., the active step has moved past step 1).

**The `"use client"` directive is required** because the component uses `React.createContext`, `React.useContext`, and conditional rendering based on context values.

**No external dependencies**: The stepper has zero npm dependencies beyond `lucide-react` (which is already a project dependency used by many components). The registry entry therefore has **no** `dependencies` field, matching the pattern of `card`.

---

### 2. File: `stepper-demo.tsx` -- Exact Code

```typescript
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        <StepperItem step={0}>
          <StepperTrigger />
          <StepperTitle>Account</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={1}>
          <StepperTrigger />
          <StepperTitle>Profile</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={2}>
          <StepperTrigger />
          <StepperTitle>Complete</StepperTitle>
        </StepperItem>
      </Stepper>
      <StepperContent step={0} activeStep={activeStep}>
        <div className="rounded-lg border p-4 text-sm text-muted-foreground">
          Set up your account details.
        </div>
      </StepperContent>
      <StepperContent step={1} activeStep={activeStep}>
        <div className="rounded-lg border p-4 text-sm text-muted-foreground">
          Fill in your profile information.
        </div>
      </StepperContent>
      <StepperContent step={2} activeStep={activeStep}>
        <div className="rounded-lg border p-4 text-sm text-muted-foreground">
          You&apos;re all set!
        </div>
      </StepperContent>
      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(0, prev - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((prev) => Math.min(2, prev + 1))}
          disabled={activeStep === 2}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

**Wait -- there is a problem.** `StepperContent` in this demo is placed *outside* the `<Stepper>` provider, so it cannot use `useStepper()`. There are two clean solutions:

**Option A (recommended)**: Place `StepperContent` inside the `<Stepper>` wrapper and have it read `activeStep` from context. This is the clean compound-component pattern.

**Option B**: Make `StepperContent` accept an explicit `activeStep` prop as a fallback.

I recommend **Option A** for compound-component consistency. The corrected demo:

```typescript
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        <StepperItem step={0}>
          <StepperTrigger />
          <StepperTitle>Account</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={1}>
          <StepperTrigger />
          <StepperTitle>Profile</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={2}>
          <StepperTrigger />
          <StepperTitle>Complete</StepperTitle>
        </StepperItem>
        <StepperContent step={0}>
          <div className="rounded-lg border p-4 text-sm text-muted-foreground">
            Set up your account details.
          </div>
        </StepperContent>
        <StepperContent step={1}>
          <div className="rounded-lg border p-4 text-sm text-muted-foreground">
            Fill in your profile information.
          </div>
        </StepperContent>
        <StepperContent step={2}>
          <div className="rounded-lg border p-4 text-sm text-muted-foreground">
            You&apos;re all set!
          </div>
        </StepperContent>
      </Stepper>
      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(0, prev - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((prev) => Math.min(2, prev + 1))}
          disabled={activeStep === 2}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

However, this introduces a layout concern: `StepperContent` divs sitting as direct children inside a flex-row `Stepper` container. This requires the `Stepper` root to use `flex-wrap` or a different layout approach.

**Revised architecture**: The cleanest approach is to make the `Stepper` root **not** constrain its layout to flex-row. Instead, use `group/stepper` so children can query the orientation via `group-data-[orientation=...]/stepper:` selectors. The step indicators row should be a natural flow within the children, and the Stepper root is just a context provider with minimal styling. But this deviates from the spec that says Stepper renders a flex-layout div.

**Final recommended approach**: Keep the `Stepper` as a `flex-col` wrapper always, and have the `StepperItem` elements naturally flow horizontally or vertically via a wrapper. Let me reconsider the structure.

The cleanest compound component pattern that works:

- `Stepper` renders `<div className="flex flex-col gap-4">` (always column -- it stacks the step indicator row and the content area)
- Inside the demo, wrap `StepperItem` elements in a plain `<div className="flex items-center gap-4">` for the horizontal step row
- Or: the `Stepper` wraps everything in column, and provides orientation context, but the step items and content are siblings

Actually, re-reading the requirements more carefully: `Stepper` should have "Flex layout appropriate to orientation." This means:

- Horizontal orientation: the `StepperItem` elements flow in a row
- `StepperContent` is naturally below the row

The simplest clean solution: **The `Stepper` root renders a flex-col div always**. It uses a `group/stepper` class so children can query orientation. The stepper items are placed inside a header-like row by the user or automatically. But the requirements say Stepper is the root and StepperItem goes directly inside.

Let me settle this with the most pragmatic design: The `Stepper` root renders `flex-col`, and internally provides context. The demo places the step indicator items in a separate wrapper div and the content below. This keeps things clean:

**Final stepper.tsx code** (revised for clean layout):

```typescript
